import{_ as t,o as i,c as s,ag as r}from"./chunks/framework.WmBmIPw-.js";const _=JSON.parse('{"title":"基础启发式（Simple Heuristics）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/simple-heuristics.md","filePath":"or-opt/simple-heuristics.md","lastUpdated":1777189290000}'),a={name:"or-opt/simple-heuristics.md"};function o(l,e,p,c,m,n){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="基础启发式-simple-heuristics" tabindex="-1">基础启发式（Simple Heuristics） <a class="header-anchor" href="#基础启发式-simple-heuristics" aria-label="Permalink to &quot;基础启发式（Simple Heuristics）&quot;">​</a></h1><p>基础启发式指面向问题结构直接设计的规则、贪心、邻域上短链改进等，通常不依赖跨问题的通用元层迭代框架。文献中常再分为构造式与改进式（定义与 <a href="./heuristic-algorithms.html">启发式算法总览</a> 中第一类下两子折叠一致）：</p><ul><li><strong>构造式</strong>（constructive）：从空或部分解逐步追加至完整可行解，或等价的逐步生成。</li><li><strong>改进式</strong>（improvement）：从已有可行解出发，在邻域内作有限步改进或局部搜子过程。</li></ul><p>二者常组合为「先构造、再改进」。分类与与元启发式、精确法的配合见 <a href="./heuristic-algorithms.html">启发式算法总览</a> 中「一、基础启发式」及下两项折叠。</p><blockquote><p>本页为栏目占位，后续可在此补：典型算例、贪心反例、与精确法/元启发式衔接的用法等。</p></blockquote>',5)])])}const h=t(a,[["render",o]]);export{_ as __pageData,h as default};
